#!/usr/bin/env node

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

function runSecureNpmInstall() {
  try {
    // Verify package-lock.json exists for reproducible builds
    const lockFilePath = path.join(process.cwd(), 'package-lock.json');
    if (!fs.existsSync(lockFilePath)) {
      console.error('ERROR: package-lock.json not found. Commit it to ensure reproducible builds.');
      process.exit(1);
    }

    // Verify package.json exists
    const packageJsonPath = path.join(process.cwd(), 'package.json');
    if (!fs.existsSync(packageJsonPath)) {
      console.error('ERROR: package.json not found.');
      process.exit(1);
    }

    console.log('Installing dependencies securely...');
    
    // Use npm ci for CI/CD - it's faster, more reliable, and secure
    // --ignore-scripts prevents arbitrary code execution during install
    // --audit checks for known vulnerabilities
    execSync('npm ci --ignore-scripts --audit', {
      stdio: 'inherit',
      env: {
        ...process.env,
        NODE_ENV: 'production'
      }
    });

    console.log('Dependency installation complete.');
    
    // Run audit to check for vulnerabilities
    console.log('Running security audit...');
    try {
      execSync('npm audit --audit-level=moderate', {
        stdio: 'inherit'
      });
    } catch (auditError) {
      console.error('Security vulnerabilities found. Please review and fix.');
      process.exit(1);
    }

    console.log('Installation completed securely.');
    
  } catch (error) {
    console.error('Installation failed:', error.message);
    process.exit(1);
  }
}

runSecureNpmInstall();